+    assert_eq!(
+        result.live.semantics.resource_surface.counters["eof_after_client_half_close"],
+        1
+    );
+    assert_eq!(
+        result.live.semantics.resource_surface.counters["ack_after_half_close"],
+        1
+    );
+    assert_eq!(
